import os
import boto3
from botocore.exceptions import NoCredentialsError, PartialCredentialsError
import joblib

def load_latest_model_from_s3(bucket_name, model_path):
    s3 = boto3.client('s3')
    try:
        response = s3.list_objects_v2(Bucket=bucket_name, Prefix=model_path)
        if 'Contents' in response:
            latest_model = max(response['Contents'], key=lambda x: x['LastModified'])
            model_key = latest_model['Key']
            s3.download_file(bucket_name, model_key, '/tmp/latest_model.pkl')
            model = joblib.load('/tmp/latest_model.pkl')
            return model
        else:
            raise FileNotFoundError("No models found in the specified path.")
    except (NoCredentialsError, PartialCredentialsError):
        raise PermissionError("AWS credentials not found or incomplete.")
    except Exception as e:
        raise RuntimeError(f"Failed to load model: {str(e)}")

def main():
    model_path = os.getenv('MODEL_PATH')
    if not model_path:
        raise EnvironmentError("MODEL_PATH environment variable not set.")
    
    bucket_name = 'your-s3-bucket-name'
    model = load_latest_model_from_s3(bucket_name, model_path)
    # Use the loaded model for inference
    # Example: predictions = model.predict(data)

if __name__ == "__main__":
    main()